// app/admin/layout.tsx

import { redirect } from 'next/navigation'
import { headers } from 'next/headers'
import { getSession } from '@/lib/auth'
import dbConnect from '@/lib/mongodb'
import Admin from '@/models/Admin'

/**
 * Checks if the application requires initial setup.
 * Treat as production-grade: includes error logging and explicit return types.
 */
async function checkSetupRequired(): Promise<boolean> {
  try {
    await dbConnect()
    const admin = await Admin.findOne({})
    return !admin
  } catch (error) {
    console.error('Database connection error during setup check:', error)
    return true
  }
}

export default async function AdminLayout({
  children,
}: {
  children: React.ReactNode
}) {
  const session = await getSession()
  const setupRequired = await checkSetupRequired()

  // Retrieve headers to inspect the current request path
  const headerRequest = await headers()
  // In Next.js, 'x-url' or 'referer' can help identify the target path in some environments,
  // but checking the specific layout structure is more reliable.
  const host = headerRequest.get('host')
  const protocol = process.env.NODE_ENV === 'production' ? 'https' : 'http'
  
  // Note: Middleware is usually preferred for this, but for a layout-based fix:
  // We check if the children being rendered belong to the login or setup pages.
  // Since we cannot easily see the child route in the layout, we rely on the referer 
  // or a custom header if available. 
  
  // Refined Logic: If setup is required, allow all admin children to render (setup page)
  if (setupRequired) {
    return <>{children}</>
  }

  // To prevent the 307 loop, we must avoid calling redirect() if the user 
  // is already navigating to the login page. 
  // We use the header 'x-next-url' which Next.js sets internally during transitions.
  const currentPath = headerRequest.get('x-next-url') || ''
  const isLoginPage = currentPath.startsWith('/admin/login')

  if (isLoginPage) {
    return <>{children}</>
  }

  // Redirect to login if no session is found and we aren't already going to login
  if (!session) {
    redirect('/admin/login')
  }

  return <>{children}</>
}